using UnityEngine;using System;
public class ScoreManager : MonoBehaviour{public static ScoreManager Instance{get;private set;}public int CurrentScore{get;private set;}public int HighScore{get;private set;}public Action<int> OnScoreChanged;public Action<int> OnHighScoreBeaten;private bool beaten;private void Awake(){if(Instance==null)Instance=this;else{Destroy(gameObject);return;}HighScore=PlayerPrefs.GetInt("HighScore",0);}public void ResetScore(){CurrentScore=0;beaten=false;OnScoreChanged?.Invoke(0);}public void AddScore(int a){CurrentScore+=a;OnScoreChanged?.Invoke(CurrentScore);if(CurrentScore>HighScore){if(!beaten){beaten=true;OnHighScoreBeaten?.Invoke(CurrentScore);}HighScore=CurrentScore;PlayerPrefs.SetInt("HighScore",HighScore);PlayerPrefs.Save();}}public void DoubleScore(){AddScore(CurrentScore);}}